#include <chrono>
#include <iomanip>
#include <sstream>

namespace query_active_users_posts {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  sqlgen::DateTime created_at;
};

struct ActiveUser {
  static constexpr const char* tablename = "ActiveUserView";
  static constexpr bool is_view = true;
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

std::vector<ActiveUser> query_active_users_posts() {
    using namespace sqlgen::literals;

    // 1. Connect to SQLite database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        throw std::runtime_error("Failed to connect to database");
    }
    auto conn = conn_result.value();

    // 2. Create User and Post tables
    auto create_user_result = conn | sqlgen::create_table<User>;
    if (!create_user_result) {
        throw std::runtime_error("Failed to create User table");
    }

    auto create_post_result = conn | sqlgen::create_table<Post>;
    if (!create_post_result) {
        throw std::runtime_error("Failed to create Post table");
    }

    // 3. Execute the query to find active users
    auto query_result = conn | sqlgen::read<std::vector<ActiveUser>>
                        | sqlgen::inner_join<Post, "p">("u.user_id"_c == "p.user_id"_c)
                        | sqlgen::where(("p.created_at"_c >= "2025-12-01") && 
                                       ("p.created_at"_c <= "2025-12-31"))
                        | sqlgen::distinct;

    if (!query_result) {
        throw std::runtime_error("Query execution failed");
    }

    // 4. Return the result
    return query_result.value();
}

