  std::optional<std::string> genre;
  std::optional<double> max_price;
};

std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
  using namespace sqlgen::literals;

  // 1. Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return {}; // Return empty vector on connection failure
  }
  auto conn = *conn_result;

  // 2. Start with base SELECT query and build dynamic WHERE conditions
  auto query = sqlgen::read<std::vector<Book>>;

  // 3. Dynamically add WHERE clauses based on non-null input parameters
  auto condition = sqlgen::transpilation::conditions::always_true;

  if (filters.title_keyword) {
    condition = condition && ("title"_c.like("%" + *filters.title_keyword + "%"));
  }

  if (filters.min_year) {
    condition = condition && ("year"_c >= *filters.min_year);
  }

  if (filters.genre) {
    condition = condition && ("genre"_c == *filters.genre);
  }

  if (filters.max_price) {
    condition = condition && ("price"_c <= *filters.max_price);
  }

  // 4. Apply the condition to the query
  auto filtered_query = query | sqlgen::where(condition);

  // 5. Execute the query and return results
  auto result = filtered_query(conn);
  if (result) {
    return *result;
  } else {
    return {}; // Return empty vector on query execution failure
  }
}

}  // namespace query_search_books_by_criteria
