```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }

  auto conn = conn_result.value();

  // 2. Begin a transaction
  auto transaction_result = conn | sqlgen::begin_transaction;
  if (!transaction_result) {
    return false;
  }

  auto transaction = transaction_result.value();

  // 3. Read the from_account to check balance
  auto from_account_result = (sqlgen::read<std::vector<Account>> | 
                           sqlgen::where("account_id"_c == from_account_id))(transaction);

  if (!from_account_result) {
    transaction | sqlgen::rollback;
    return false;
  }

  auto from_account = from_account_result.value();
  if (from_account.empty()) {
    transaction | sqlgen::rollback;
    return false;
  }

  auto from_balance = from_account[0].balance;
  if (from_balance < amount) {
    transaction | sqlgen::rollback;
    return false;
  }

  // 4. Update from_account: balance = balance - amount
  auto update_from_result = (sqlgen::update<Account>("balance"_c.set(from_balance - amount)) | 
                          sqlgen::where("account_id"_c == from_account_id))(transaction);

  if (!update_from_result) {
    transaction | sqlgen::rollback;
    return false;
  }

  // 5. Update to_account: balance = balance + amount
  auto to_account_result = (sqlgen::read<std::vector<Account>> | 
                         sqlgen::where("account_id"_c == to_account_id))(transaction);

  if (!to_account_result) {
    transaction | sqlgen::rollback;
    return false;
  }

  auto to_account = to_account_result.value();
  if (to_account.empty()) {
    transaction | sqlgen::rollback;
    return false;
  }

  auto to_balance = to_account[0].balance;
  auto update_to_result = (sqlgen::update<Account>("balance"_c.set(to_balance + amount)) | 
                          sqlgen::where("account_id"_c == to_account_id))(transaction);

  if (!update_to_result) {
    transaction | sqlgen::rollback;
    return false;
  }

  // 6. Commit the transaction
  auto commit_result = transaction | sqlgen::commit;
  if (!commit_result) {
    transaction | sqlgen::rollback;
    return false;
  }

  return true;
}

}  // namespace transaction_transfer_funds
```

## Key Implementation Points:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to establish connection
2. **Transaction Management**: Uses `sqlgen::begin_transaction`, `sqlgen::commit`, and `sqlgen::rollback`
3. **Balance Check**: Reads from_account using `sqlgen::read` with `where` clause to verify sufficient funds
4. **Update Operations**: Uses `sqlgen::update` with `set` operations for both accounts
5. **Error Handling**: Properly handles errors and rolls back transaction on failure
6. **Fluent API**: Uses the `operator|` syntax for chaining operations as shown in the reference materials

The implementation follows the exact sequence specified in the assessment objectives and uses the appropriate sqlgen functions and patterns from the reference materials.

