  EXPECT_DOUBLE_EQ(m1.discounted_total, 450.0);
  EXPECT_DOUBLE_EQ(m1.final_total, 472.5);
  EXPECT_DOUBLE_EQ(m1.unit_cost, 100.0);
  EXPECT_EQ(m1.quantity_group, 5);
