    return SelectFrom<TableOrQueryType, AliasType, FieldsType, NewJoinsType,
                      WhereType, GroupByType, OrderByType, LimitType, ToType>{
        .fields_ = _s.fields_, .from_ = _s.from_, .joins_ = joins};
