struct User {
  sqlgen::PrimaryKey<int> id;
  std::string name;
  int age;
};

/**
 * This function demonstrates using read_to_select_from.
 * Returns: std::string.
 */
inline std::string read_to_select_from_usage() {
  using namespace sqlgen::literals;

  // Create WHERE condition: age > 18
  auto where_condition = "age"_c > 18;

  // Create LIMIT clause: limit 10
  auto limit_clause = sqlgen::limit(10);

  // Generate the SELECT query for User with WHERE and LIMIT
  auto query = sqlgen::transpilation::read_to_select_from<User>(
      where_condition, 
      limit_clause
  );

  // Convert the query to SQL string using sqlite::to_sql
  return sqlgen::sqlite::to_sql(query);
}

}  // namespace read_to_select_from_usage
```

